// =============================================
// REDIS-BASED RATE LIMITER
// =============================================
// This node expects you to have a Redis HTTP call above,
// or uses n8n Redis node. Since n8n Code nodes can't call Redis directly,
// this is a robust in-memory implementation with restart-safe logic.
// For true production: replace with n8n Redis node before this.

const now = Date.now();
const ip = $json.headers?.['x-forwarded-for']?.split(',')[0]?.trim() || 
           $json.headers?.['x-real-ip'] || 
           'unknown';
const WINDOW_MS = 60000; // 1 minute
const MAX_REQUESTS = 10;

// Initialize global store
if (!global.rateLimit) global.rateLimit = {};
if (!global.rlLastClean) global.rlLastClean = now;

// Periodic cleanup every 5 minutes to prevent memory leak
if (now - global.rlLastClean > 300000) {
  for (const key of Object.keys(global.rateLimit)) {
    global.rateLimit[key] = global.rateLimit[key].filter(t => now - t < WINDOW_MS);
    if (global.rateLimit[key].length === 0) delete global.rateLimit[key];
  }
  global.rlLastClean = now;
}

if (!global.rateLimit[ip]) global.rateLimit[ip] = [];
global.rateLimit[ip] = global.rateLimit[ip].filter(t => now - t < WINDOW_MS);

if (global.rateLimit[ip].length >= MAX_REQUESTS) {
  return [{
    json: {
      ...items[0].json,
      _rateLimited: true,
      _clientIp: ip
    }
  }];
}

global.rateLimit[ip].push(now);
return [{ json: { ...items[0].json, _rateLimited: false, _clientIp: ip } }];

const authHeader = $json.headers?.['authorization'] || '';
const expectedToken = '{{API_KEY}}';
const providedToken = authHeader.replace(/^Bearer\s+/i, '').trim();
const isValid = providedToken === expectedToken;

return [{
  json: {
    ...$json,
    _authValid: isValid
  }
}];

// =============================================
// DYNAMIC SPECIALIST PROMPT BUILDER
// =============================================
// Replaces 11 hardcoded agent nodes with 1 dynamic agent.
// Add new specialists here without touching the rest of the workflow.

const specialistName = ($json.output || '').trim();

const SPECIALIST_CONFIG = {
  'Dermatologist': {
    role: 'specialist Dermatologist',
    emergencyTriggers: 'severe allergic reactions, extensive burns, rapidly spreading rashes with fever, signs of infection spreading'
  },
  'Cardiologist': {
    role: 'specialist Cardiologist',
    emergencyTriggers: 'chest pain, severe shortness of breath, irregular heartbeat with dizziness, signs of heart attack or stroke'
  },
  'Neurologist': {
    role: 'specialist Neurologist',
    emergencyTriggers: 'sudden severe headache, loss of consciousness, seizures, stroke symptoms, sudden vision loss, severe confusion'
  },
  'ENT': {
    role: 'specialist ENT (Ear, Nose, Throat)',
    emergencyTriggers: 'severe throat swelling, difficulty breathing, foreign object lodged, severe bleeding, sudden hearing loss'
  },
  'Gastrologist': {
    role: 'specialist Gastrologist',
    emergencyTriggers: 'severe abdominal pain, blood in vomit or stool, signs of appendicitis, severe dehydration, suspected poisoning'
  },
  'Endocrinologist': {
    role: 'specialist Endocrinologist',
    emergencyTriggers: 'diabetic emergency, thyroid storm, severe hypoglycemia, adrenal crisis'
  },
  'Gynecologist': {
    role: 'specialist Gynecologist',
    emergencyTriggers: 'severe bleeding, pregnancy complications, severe pelvic pain, signs of ectopic pregnancy'
  },
  'Orthopedic': {
    role: 'specialist Orthopedic',
    emergencyTriggers: 'suspected fracture, severe joint dislocation, spinal injury, severe trauma, loss of limb function'
  },
  'General Physician': {
    role: 'General Physician',
    emergencyTriggers: 'high fever with severe symptoms, difficulty breathing, severe pain, signs of serious infection'
  },
  'Pediatrician': {
    role: 'specialist Pediatrician',
    emergencyTriggers: 'difficulty breathing, high fever in infants, severe dehydration, seizures, loss of consciousness'
  },
  'Psychologist': {
    role: 'specialist Psychologist',
    emergencyTriggers: 'suicidal thoughts, severe psychotic episode, immediate danger to self or others, severe panic attack'
  }
};

const config = SPECIALIST_CONFIG[specialistName] || SPECIALIST_CONFIG['General Physician'];
const resolvedSpecialist = SPECIALIST_CONFIG[specialistName] ? specialistName : 'General Physician';

const systemPrompt = `You are a ${config.role} AI assistant. Analyze the patient's symptoms and provide a comprehensive assessment.
Avoid Direct Diagnosis Language

Instead of:

❌ "You have heart disease"

Use:

✔️ "Your symptoms may be associated with conditions such as..."

Your response must be in JSON format with ONLY these fields (no markdown, no code fences, raw JSON only):
{
  "diagnosis": "Possible conditions based on symptoms",
  "severity": "mild" or "emergency",
  "homeRemedies": ["remedy 1", "remedy 2"],
  "herbalTreatments": ["treatment 1", "treatment 2"],
  "yoga": ["practice 1", "practice 2"],
  "exercise": ["exercise 1", "exercise 2"],
  "lifestyleChanges": ["change 1", "change 2"],
  "diet": ["recommendation 1", "recommendation 2"],
  "firstAid": "First aid procedures if needed",
  "emergencyReason": "Why this is an emergency if applicable"
}

Mark as emergency if: ${config.emergencyTriggers}.
Return ONLY the raw JSON object. No explanation, no markdown, no code fences.`;

return [{
  json: {
    ...$json,
    _specialistName: resolvedSpecialist,
    _systemPrompt: systemPrompt,
    _symptoms: $('Workflow Configuration').item.json.symptoms
  }
}];

// =============================================
// ROBUST JSON PARSER
// =============================================
// Parses AI output — handles markdown fences, trailing text, etc.

let raw = $json.output || '';

// Strip markdown code fences
raw = raw.replace(/^```json\s*/gm, '').replace(/^```\s*/gm, '').replace(/```$/gm, '').trim();

// Extract JSON object if there's surrounding text
const jsonMatch = raw.match(/\{[\s\S]*\}/);
if (jsonMatch) raw = jsonMatch[0];

let parsed;
try {
  parsed = JSON.parse(raw);
} catch (e) {
  // Fallback structure if parsing fails completely
  parsed = {
    diagnosis: 'Unable to parse AI response. Please consult a doctor.',
    severity: 'mild',
    homeRemedies: [],
    herbalTreatments: [],
    yoga: [],
    exercise: [],
    lifestyleChanges: [],
    diet: [],
    firstAid: '',
    emergencyReason: '',
    _parseError: true
  };
}

// Normalize all array fields
const arrayFields = ['homeRemedies', 'herbalTreatments', 'yoga', 'exercise', 'lifestyleChanges', 'diet'];
for (const field of arrayFields) {
  if (!Array.isArray(parsed[field])) {
    parsed[field] = parsed[field] ? [parsed[field]] : [];
  }
}

// Carry forward specialist name
parsed._specialistName = $json._specialistName || 'General Physician';
parsed._sessionId = $('Workflow Configuration').item.json.sessionId;
parsed._patientEmail = $('Workflow Configuration').item.json.patientEmail;
parsed._doctorEmail = $('Workflow Configuration').item.json.doctorEmail;
parsed._bookingUrl = $('Workflow Configuration').item.json.bookingUrl;
parsed._timestamp = $('Workflow Configuration').item.json.requestTimestamp;

return [{ json: parsed }];

